const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;
const chatId = $env.TELEGRAM_CHAT_ID;
if (!supabaseUrl || !serviceKey) throw new Error('Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY in n8n');
if (!chatId) throw new Error('Missing TELEGRAM_CHAT_ID in n8n');
function phtDate() { const parts = new Intl.DateTimeFormat('en-US', { timeZone: 'Asia/Manila', year: 'numeric', month: '2-digit', day: '2-digit' }).formatToParts(new Date()); const pick = (type) => parts.find((part) => part.type === type).value; return `${pick('year')}-${pick('month')}-${pick('day')}`; }
const today = phtDate();
const response = await fetch(`${supabaseUrl}/rest/v1/rpc/get_mmf_health_report`, { method: 'POST', headers: { apikey: serviceKey, Authorization: `Bearer ${serviceKey}`, 'Content-Type': 'application/json' }, body: JSON.stringify({ check_date: today }) });
if (!response.ok) throw new Error(`MMF health RPC failed ${response.status}: ${await response.text()}`);
const issues = await response.json();
let text;
if (!issues.length) { text = `Truva MMF health: OK\nDate: ${today}\nAll active PHP UITF targets have scraper-sourced rows with yields and BTR_91D benchmark values.`; } else { const lines = issues.slice(0, 20).map((issue) => `- ${issue.provider} - ${issue.name}: ${issue.issue_type} - ${issue.detail}`); const more = issues.length > 20 ? `\n...and ${issues.length - 20} more issue(s).` : ''; text = `Truva MMF health: ACTION NEEDED\nDate: ${today}\nIssues: ${issues.length}\n${lines.join('\n')}${more}`; }
return [{ json: { chatId, text, date: today, issue_count: issues.length } }];
